+import type { Aspect, AspectInput, AspectRecord } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<T> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input as Trait];
+        for (const constituent of constituents) {
+            if (isRelation(constituent) || constituent[$internal]?.relation) {
+                throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            }
+            if (traits.includes(constituent)) continue;
+            for (const field of Object.keys(constituent.schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Koota: Aspect constituents cannot share the field "${field}".`);
+                }
+                fields.add(field);
+            }
+            traits.push(constituent);
+        }
+    }
+
+    const schema = Object.assign({}, ...traits.map((trait) => trait.schema));
+    const Aspect = Object.assign((params?: AspectRecord<T>) => [Aspect, params], {
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits),
+        schema: Object.freeze(schema),
+    }) as Aspect<T>;
+
+    return Aspect;
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): AspectRecord<any> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) {
+        const value = getTrait(world, entity, trait);
+        if (value) Object.assign(result, value);
+    }
+    return result;
+}
+
+export function setAspect(
+    world: World,
+    entity: Entity,
+    aspect: Aspect,
+    value: AspectRecord<any> | ((previous: AspectRecord<any>) => AspectRecord<any>),
+    triggerChanged = true
+) {
+    const next = value instanceof Function ? value(getAspect(world, entity, aspect)!) : value;
+    for (const trait of aspect.traits) {
+        const fields = pickFields(trait, next);
+        if (Object.keys(fields).length) setTrait(world, entity, trait, fields, triggerChanged);
+    }
+}
+
+export function addAspect(
+    world: World,
+    entity: Entity,
+    aspect: Aspect,
+    value?: AspectRecord<any>
+) {
+    for (const trait of aspect.traits) {
+        if (hasTrait(world, entity, trait)) continue;
+        const fields = value && pickFields(trait, value);
+        addTrait(world, entity, fields && Object.keys(fields).length ? [trait, fields] : trait);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function pickFields(trait: Trait, value: Record<string, unknown>): Record<string, unknown> {
+    const result: Record<string, unknown> = {};
+    for (const field of Object.keys(trait.schema)) {
+        if (field in value) result[field] = value[field];
+    }
+    return result;
+}
